const body = $json;
const rawInput = body.chatInput || body.message || body.text || body.output || '';
const chatInput = String(rawInput).replace(/data:image\/[a-zA-Z0-9.+-]+;base64,[A-Za-z0-9+/=]+/g, '[uploaded image data removed]').slice(0, 12000);
const safeAttachments = (body.attachments || []).slice(0, 8).map(item => {
  const url = String(item?.url || item?.download_url || item?.image_url || '');
  const safeUrl = url.startsWith('data:') && url.length > 2000 ? '[inline data removed]' : url.slice(0, 1200);
  return {
    type: item?.type || item?.file_type || 'file',
    name: String(item?.name || item?.file_name || 'attachment').slice(0, 180),
    mimeType: item?.mimeType || item?.mime_type || null,
    url: safeUrl,
    download_url: String(item?.download_url || safeUrl || '').slice(0, 1200),
    documentId: item?.documentId || item?.document_id || null
  };
});
return [{ json: {
  ...body,
  chatInput,
  message: chatInput,
  sessionId: body.sessionId || body.conversationId || body.context?.userId || 'anonymous',
  conversationId: body.conversationId || null,
  context: body.context || {},
  metadata: body.metadata || {},
  attachments: safeAttachments,
  action: body.action || 'sendMessage'
}}];

const request = $('02 Normalize Chat Payload').first().json;
const context = request.context || {};

// This node is intentionally local-first. n8n on this server blocks $env,
// and $vars may be empty during manual tests. The frontend already sends
// user context, so do not crash the workflow when Supabase enrichment is
// not configured yet.
return [{ json: {
  ...request,
  profile: {
    id: context.userId || null,
    full_name: context.fullName || null,
    email: context.email || null,
    primary_role: context.role || 'employee',
    department: context.department || null,
    organization_id: context.organizationId || null
  },
  supabaseContextStatus: context.userId ? 'frontend_context' : 'anonymous_or_manual_test'
}}];

const request = $('03 Prepare User Context (Supabase Optional)').first().json;
const profile = request.profile || {};
const chatInput = request.chatInput || request.message || '';
return [{ json: {
  ...request,
  chatInput,
  message: chatInput,
  context: {
    ...request.context,
    userId: request.context.userId || profile.id || 'anonymous',
    fullName: request.context.fullName || profile.full_name || 'Workspace User',
    email: request.context.email || profile.email || null,
    role: request.context.role || profile.primary_role || 'employee',
    department: request.context.department || profile.department || null,
    organizationId: request.context.organizationId || profile.organization_id || 'workspace-default',
    currentModule: request.context.currentModule || 'ai-workspace',
    timezone: request.context.timezone || 'Africa/Harare',
    channel: request.context.channel || 'web'
  }
}}];

const chatInput = $json.chatInput || $json.message || '';
const message = chatInput.toLowerCase();
const attachments = $json.attachments || [];
const hasImageAttachment = attachments.some(item => item?.type === 'image' || String(item?.mimeType || '').startsWith('image/'));
const hasDocumentAttachment = attachments.some(item => item?.type === 'document' || /pdf|text|markdown|csv|json|word|document/i.test(String(item?.mimeType || item?.name || '')));
let route = 'main_agent';
if (hasDocumentAttachment || /document|file|pdf|policy|summarize this|action items|deadline|extract text|invoice|receipt/.test(message)) route = 'document_qa';
if (hasImageAttachment || /what can you see|analy[sz]e image|identify this|what car|car model|read this image|extract text from image|ocr image/.test(message)) route = 'image_analysis';
if (/who|team|department|responsible|maintain|built codex|developer/.test(message)) route = 'people_directory';
if (/website|external company|research|find online|official site/.test(message)) route = 'web_research';
if (/logo|hero image|gallery|open graph|og:image|favicon/.test(message)) route = 'image_fetch';
if (/generate.*image|create.*image|draw|make.*picture|image of/.test(message)) route = 'image_generation';
if (/code|typescript|react|next|tailwind|supabase|node|expo|bug|error/.test(message)) route = 'code_assistant';
return [{ json: { ...$json, chatInput, message: chatInput, route, allowed: true } }];

const source = $('05 Permission + Tool Router').first().json;
return [{ json: {
  success: true,
  type: 'text',
  message: 'Image generation is almost ready, but the OpenAI credential is not connected to the image generation node. Open Generate Image - OpenAI Direct, select your OpenAi account credential, save and activate the workflow, then try again.',
  output: 'Image generation is almost ready, but the OpenAI credential is not connected to the image generation node. Open Generate Image - OpenAI Direct, select your OpenAi account credential, save and activate the workflow, then try again.',
  conversationId: source.conversationId || null,
  data: {},
  attachments: [],
  sources: []
}}];

const source = $('05 Permission + Tool Router').first().json;
const prompt = (source.message || source.chatInput || 'generated image').replace(/\n\[Context\][\s\S]*$/, '').trim();
const b64 = $json.data?.[0]?.b64_json;
if (!b64) {
  const detail = $json.error?.message || $json.message || $json.error || 'OpenAI did not return image data.';
  const message = `I could not return a generated image yet. OpenAI image generation failed: ${String(detail).slice(0, 300)}`;
  return [{ json: {
    success: true,
    type: 'text',
    message,
    output: message,
    conversationId: source.conversationId || null,
    data: { prompt },
    attachments: [],
    sources: []
  }}];
}
const imageUrl = `data:image/png;base64,${b64}`;
const slug = prompt.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 48) || 'codex-image';
return [{ json: {
  success: true,
  type: 'generated_image',
  message: 'Image generated successfully.',
  output: 'Image generated successfully.',
  conversationId: source.conversationId || null,
  data: { prompt },
  attachments: [{
    type: 'image',
    name: `${slug}.png`,
    url: imageUrl,
    download_url: imageUrl,
    metadata: { source: 'openai_images', model: 'gpt-image-1' }
  }],
  sources: []
}}];

let output = $json.output || $json.message || $json.text || 'I could not produce a verified response.';
const rawAttachments = Array.isArray($json.attachments) ? $json.attachments : [];
const isBrowserUrl = value => typeof value === 'string' && /^(https?:|data:image\/|blob:)/i.test(value);
let attachments = rawAttachments
  .filter(item => item && typeof item === 'object')
  .map(item => ({
    type: item.type || item.file_type || 'file',
    name: item.name || item.file_name || 'codex-file',
    url: item.url || item.image_url || item.download_url || '',
    download_url: item.download_url || item.url || item.image_url || '',
    metadata: item.metadata || {}
  }))
  .filter(item => isBrowserUrl(item.url) || isBrowserUrl(item.download_url));
const rawB64 = $json.data?.[0]?.b64_json || $json.data?.b64_json || $json.b64_json;
if (rawB64 && typeof rawB64 === 'string') {
  const imageUrl = `data:image/png;base64,${rawB64}`;
  attachments.push({
    type: 'image',
    name: $json.file_name || 'codex-generated-image.png',
    url: imageUrl,
    download_url: imageUrl,
    metadata: { source: 'openai_images' }
  });
}
let hasVisibleImage = attachments.some(item => String(item.type || '').toLowerCase().includes('image') && (isBrowserUrl(item.url) || isBrowserUrl(item.download_url)));
const claimsImageGenerated = /image\s+(has been\s+)?(created|generated)|generated\s+image|download\s+.*image/i.test(output);
if (claimsImageGenerated && !hasVisibleImage) {
  output = 'I could not return a generated image because OpenAI did not provide image data in the tool result. Please check the Image Generation Tool execution in n8n.';
  attachments = [];
}
return [{ json: {
  success: true,
  type: $json.type || (hasVisibleImage ? 'generated_image' : 'text'),
  message: output,
  output,
  conversationId: $('04 Merge Request + User Context').first().json.conversationId || null,
  data: $json.data || {},
  attachments,
  sources: $json.sources || []
}}];

const body = $json.body || $json;
const parsedContext = typeof body.context === 'string' ? JSON.parse(body.context || '{}') : (body.context || {});
const parsedMetadata = typeof body.metadata === 'string' ? JSON.parse(body.metadata || '{}') : (body.metadata || {});
const uploadBinary = $binary?.file || $binary?.data || null;
const driveFileId = body.drive_file_id || body.driveFileId || body.googleDriveFileId || body.fileId || body.id || null;
const json = {
  ...body,
  context: parsedContext,
  metadata: parsedMetadata,
  driveFileId,
  hasUploadedBinary: Boolean(uploadBinary),
  source: uploadBinary ? 'upload' : 'google_drive',
  file_name: body.file_name || body.fileName || body.name || uploadBinary?.fileName || 'Uploaded document',
  file_type: body.file_type || body.fileType || uploadBinary?.mimeType || 'unknown',
  organization_id: body.organization_id || parsedContext.organizationId || parsedContext.organization_id || null,
  uploaded_by: body.uploaded_by || parsedContext.userId || parsedContext.user_id || null,
  department: body.department || parsedContext.department || null,
  module: body.module || parsedContext.currentModule || 'ai-workspace',
  access_level: body.access_level || 'internal',
  source_url: body.source_url || body.webViewLink || null
};
if (!uploadBinary && !driveFileId) {
  throw new Error('No uploaded file or Google Drive file id was provided.');
}
return [{ json, binary: uploadBinary ? { data: uploadBinary } : $binary }];

const source = $('Prepare Document Training Input').first().json || {};
const raw = $json.text || $json.data || $json.content || $json.markdown || '';
let text = String(raw).replace(/\u0000/g, ' ').replace(/\s+/g, ' ').trim();
const lower = text.toLowerCase();
const looksLikeHtml = /<!doctype html|<html[\s>]|<script[\s>]|window\.__|webpack|vite|next-data|<body[\s>]/i.test(text);
const tagCount = (text.match(/<[^>]+>/g) || []).length;
const wordCount = (text.match(/[a-z0-9]{2,}/gi) || []).length;
if (!text || wordCount < 8) {
  throw new Error('Document could not be read. Please upload a readable file or OCR version.');
}
if (looksLikeHtml || (tagCount > 20 && tagCount > wordCount / 3)) {
  throw new Error('Document extraction returned HTML/script content instead of document text. Check that the workflow is receiving the actual file binary, not a preview page or website URL.');
}
const chunkSize = 2200;
const overlap = 180;
const chunks = [];
for (let i = 0; i < text.length; i += chunkSize - overlap) {
  chunks.push({ json: { ...source, ...$json, chunkIndex: chunks.length, chunkText: text.slice(i, i + chunkSize), extractedTextLength: text.length } });
}
return chunks;

