const first = items[0]?.json || {};
const summaries = items.map(item => item.json.message?.content || item.json.output || '').filter(Boolean);
const detailed = summaries.join('\n\n');
return [{ json: {
  ...first,
  summary_short: summaries[0]?.slice(0, 400) || '',
  summary_detailed: detailed,
  tags: first.tags || [],
  status: 'trained',
  chunks: items.map((item, index) => ({ index, summary: item.json.message?.content || '', text: item.json.chunkText || '' }))
}}];

